    }

    // Allocate prefix sum array for field offsets
    size_t* prefix = (size_t*)malloc((F + 1) * sizeof(size_t));
    if (prefix == NULL) {
        return -1;
    }
    prefix[0] = 0;
    for (int f = 0; f < F; f++) {
        if (field_sizes[f] <= 0) {
            free(prefix);
            return -1;
        }
        size_t fs = (size_t)field_sizes[f];
        if (prefix[f] > (size_t)-1 - fs) {
            free(prefix);
            return -1;
        }
        prefix[f + 1] = prefix[f] + fs;
    }
    size_t per_record_size = prefix[F];

    // Calculate total buffer size, check for overflow
    size_t rc = (size_t)record_count;
    if (rc > (size_t)-1 / per_record_size) {
        free(prefix);
        return -1;
    }
    size_t total_size = rc * per_record_size;

    // Allocate parsed buffer
    *parsed_buffer = (char*)malloc(total_size);
    if (*parsed_buffer == NULL) {
        free(prefix);
        return -1;
    }

    // Allocate temporary arrays for field parsing
    const char** field_starts = (const char**)malloc(F * sizeof(const char*));
    size_t* field_lengths = (size_t*)malloc(F * sizeof(size_t));
    if (field_starts == NULL || field_lengths == NULL) {
        free(*parsed_buffer);
        free(prefix);
        free(field_starts);
        free(field_lengths);
        *parsed_buffer = NULL;
        return -1;
    }

    // Process each record
    for (int r = 0; r < record_count; r++) {
        const char* line = csv_data[r];
        if (line == NULL) {
            free(*parsed_buffer);
            free(prefix);
            free(field_starts);
            free(field_lengths);
            *parsed_buffer = NULL;
            return -1;
        }

        int field_count = 0;
        const char* p_line = line;
        const char* field_start = line;

        // Split line into fields
        while (*p_line!= '\0') {
            if (*p_line == ',') {
                if (field_count >= F) {
                    // Too many fields, early exit
                    field_count++;
                    break;
                }
                field_starts[field_count] = field_start;
                field_lengths[field_count] = p_line - field_start;
                field_count++;
                field_start = p_line + 1;
            }
            p_line++;
        }

        // Process the last field
        if (field_count < F) {
            field_starts[field_count] = field_start;
            field_lengths[field_count] = p_line - field_start;
            field_count++;
        } else {
            // Extra field after processing F fields
            field_count++;
        }

        // Check if field count matches expected
        if (field_count!= F) {
            free(*parsed_buffer);
            free(prefix);
            free(field_starts);
            free(field_lengths);
            *parsed_buffer = NULL;
            return -1;
        }

        // Copy fields to parsed buffer
        for (int f = 0; f < F; f++) {
            size_t len = field_lengths[f];
            if (len >= (size_t)field_sizes[f]) {
                free(*parsed_buffer);
                free(prefix);
                free(field_starts);
                free(field_lengths);
                *parsed_buffer = NULL;
                return -1;
            }
            char* dest = *parsed_buffer + (size_t)r * per_record_size + prefix[f];
            memcpy(dest, field_starts[f], len);
            dest[len] = '\0';
        }
    }

    // Clean up temporary allocations
    free(prefix);
    free(field_starts);
    free(field_lengths);

    return 0;
}

